const days=['domingo','segunda','terça','quarta','quinta','sexta','sábado'];
const now=new Date(new Date().toLocaleString('en-US',{timeZone:'America/Sao_Paulo'}));
const pad=n=>String(n).padStart(2,'0');
let r=`Hoje é ${days[now.getDay()]} ${pad(now.getDate())}/${pad(now.getMonth()+1)}/${String(now.getFullYear()).slice(2)} às ${pad(now.getHours())}:${pad(now.getMinutes())}\n`;
for(let i=1;i<=6;i++){
  const f=new Date(now); f.setDate(now.getDate()+i);
  if(i===1) r+=`Amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)}/${String(f.getFullYear()).slice(2)}\n`;
  else if(i===2) r+=`Depois de amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)}/${String(f.getFullYear()).slice(2)}\n`;
  else r+=`A próxima ${days[f.getDay()]} será dia ${pad(f.getDate())}/${pad(f.getMonth()+1)}/${String(f.getFullYear()).slice(2)}\n`;
}
return [{json:{resultado:r.trim()}}];

const txt=$input.first().json.output||'';
if(!txt.trim())return[];
const arr=txt.replace(/\\n/g,'\n').split(/\n/).map(l=>l.trim()).filter(l=>l.length>0);
return arr.map(msg=>({json:{output:msg}}));
